// // This module selects between two 16-bit inputs based on the select signal. When sel is 0, it outputs the first input; otherwise, it outputs the second input.
module mux_16bit(
    input [15:0] a,
    input [15:0] b,
    input sel,
    output [15:0] out
);

    assign out = (sel == 1'b0) ? a : b;

endmodule
